import { PROVIDER_DISPLAY } from "@repo/app-providers/client";
import type { GraphContext } from "@vendor/seo/json-ld";
import { JsonLd } from "@vendor/seo/json-ld";
import type { Metadata, Route } from "next";
import { getIntegrationPages } from "~/app/(app)/(content)/_lib/source";
import { NavLink } from "~/components/nav-link";
import {
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "~/lib/builders";
import { createMetadata } from "~/lib/content-seo";
import { getProviderIcon } from "~/lib/get-provider-icon";

export const dynamic = "force-static";

const PAGE_TITLE = "Integrations";
const PAGE_DESCRIPTION =
  "Connect Lightfast to the tools your engineering org already runs on. GitHub, Vercel, Linear, Sentry, and more — one integration, every event.";
const PAGE_URL = "https://lightfast.ai/integrations";
const FAQ = [
  {
    question: "What integrations does Lightfast support?",
    answer:
      "Lightfast integrates with GitHub and Vercel today, with Linear, Sentry, and Apollo shipping next. Each integration ingests events in real-time via OAuth and webhooks.",
  },
  {
    question: "How do I connect an integration?",
    answer:
      "Install the integration from your Lightfast workspace under Settings → Integrations. OAuth flow completes in under a minute; events start flowing immediately.",
  },
  {
    question: "Can I request a new integration?",
    answer:
      "Yes. Join the waitlist from any coming-soon integration page — demand drives our roadmap prioritisation.",
  },
];

export const metadata: Metadata = createMetadata({
  title: `${PAGE_TITLE} | Lightfast`,
  description: PAGE_DESCRIPTION,
  keywords: [
    "lightfast integrations",
    "github integration",
    "vercel integration",
    "linear integration",
    "engineering intelligence integrations",
  ],
  alternates: { canonical: PAGE_URL },
  openGraph: {
    title: "Lightfast Integrations",
    description: PAGE_DESCRIPTION,
    type: "website",
    url: PAGE_URL,
    siteName: "Lightfast",
    locale: "en_US",
  },
  twitter: {
    card: "summary_large_image",
    title: "Lightfast Integrations",
    description: PAGE_DESCRIPTION,
    site: "@lightfastai",
    creator: "@lightfastai",
  },
});

export default function IntegrationsIndexPage() {
  const pages = getIntegrationPages();

  const structuredData: GraphContext = {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      {
        "@type": "WebPage" as const,
        "@id": `${PAGE_URL}#webpage`,
        url: PAGE_URL,
        name: "Lightfast Integrations",
        description: PAGE_DESCRIPTION,
        isPartOf: { "@id": "https://lightfast.ai/#website" },
        publisher: { "@id": "https://lightfast.ai/#organization" },
      },
      buildFaqEntity(FAQ, PAGE_URL),
    ],
  };

  return (
    <div className="mx-auto w-full min-w-0 max-w-4xl pt-24 pb-32">
      <JsonLd code={structuredData} />
      <div className="mb-12">
        <h1 className="mb-4 font-medium font-pp text-4xl text-foreground">
          Integrations
        </h1>
        <p className="max-w-2xl text-lg text-muted-foreground leading-relaxed">
          {PAGE_DESCRIPTION}
        </p>
      </div>

      <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {pages.map((page) => {
          const { providerId, status: mdxStatus, title, tagline } = page.data;
          const providerComingSoon =
            providerId && "comingSoon" in PROVIDER_DISPLAY[providerId]
              ? PROVIDER_DISPLAY[providerId].comingSoon
              : false;
          const derivedStatus: "live" | "beta" | "coming-soon" =
            mdxStatus ?? (providerComingSoon ? "coming-soon" : "live");
          const Icon = providerId ? getProviderIcon(providerId) : undefined;
          const slug = page.slugs[0] ?? "";

          return (
            <NavLink
              className="group flex h-full flex-col gap-4 rounded-lg border border-border/50 bg-card/40 p-6 transition-colors hover:border-border hover:bg-card"
              href={`/integrations/${slug}` as Route}
              key={slug}
              prefetch
            >
              <div className="flex items-center justify-between">
                {Icon && (
                  <Icon aria-hidden className="size-8 text-foreground" />
                )}
                {derivedStatus !== "live" && (
                  <span className="inline-flex items-center rounded-md border border-border px-2 py-0.5 text-muted-foreground text-xs uppercase tracking-wider">
                    {derivedStatus === "coming-soon" ? "Soon" : "Beta"}
                  </span>
                )}
              </div>
              <div className="flex flex-col gap-2">
                <h2 className="font-medium font-pp text-foreground text-xl">
                  {title}
                </h2>
                <p className="text-muted-foreground text-sm leading-relaxed">
                  {tagline}
                </p>
              </div>
            </NavLink>
          );
        })}
      </div>
    </div>
  );
}

import type { GraphContext } from "@vendor/seo/json-ld";
import { JsonLd } from "@vendor/seo/json-ld";
import type { Metadata, Route } from "next";
import { getBlogPages } from "~/app/(app)/(content)/_lib/source";
import { NavLink } from "~/components/nav-link";
import {
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "~/lib/builders";
import { createMetadata } from "~/lib/content-seo";

export const dynamic = "force-static";

const PAGE_TITLE = "Blog";
const PAGE_DESCRIPTION =
  "Engineering deep-dives, product updates, and lessons from building the superintelligence layer for founders at Lightfast.";
const PAGE_URL = "https://lightfast.ai/blog";
const FAQ = [
  {
    question: "What topics does the Lightfast blog cover?",
    answer:
      "We cover engineering deep-dives on AI agent orchestration, product launches and changelogs, company updates, tutorials for integrating with Lightfast, and research on MCP tools and agent memory.",
  },
];

export const metadata: Metadata = createMetadata({
  title: `${PAGE_TITLE} | Lightfast`,
  description: PAGE_DESCRIPTION,
  keywords: [
    "lightfast blog",
    "ai engineering blog",
    "agent infrastructure",
    "mcp tools",
    "product updates",
  ],
  alternates: {
    canonical: PAGE_URL,
    types: {
      "application/rss+xml": [
        { url: "https://lightfast.ai/blog/rss.xml", title: "RSS 2.0" },
      ],
      "application/atom+xml": [
        { url: "https://lightfast.ai/blog/atom.xml", title: "Atom 1.0" },
      ],
    },
  },
  openGraph: {
    title: "Lightfast Blog – Operating Infrastructure for Agents and Apps",
    description:
      "Articles on operating infrastructure, event-driven architecture, and agent tooling.",
    type: "website",
    url: PAGE_URL,
    siteName: "Lightfast",
    locale: "en_US",
  },
  twitter: {
    card: "summary_large_image",
    title: "Lightfast Blog",
    description: PAGE_DESCRIPTION,
    site: "@lightfastai",
    creator: "@lightfastai",
  },
});

export default function BlogPage() {
  const pages = getBlogPages();

  const sortedPages = [...pages].sort((a, b) => {
    return (
      new Date(b.data.publishedAt).getTime() -
      new Date(a.data.publishedAt).getTime()
    );
  });

  const structuredData: GraphContext = {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      {
        "@type": "Blog" as const,
        "@id": `${PAGE_URL}#blog`,
        url: PAGE_URL,
        name: "Lightfast Blog",
        description: PAGE_DESCRIPTION,
        publisher: { "@id": "https://lightfast.ai/#organization" },
        blogPost: sortedPages.slice(0, 10).map((page) => ({
          "@type": "BlogPosting" as const,
          headline: page.data.title,
          description: page.data.description,
          url: `https://lightfast.ai/blog/${page.slugs[0]}`,
          datePublished: page.data.publishedAt,
        })),
      },
      buildFaqEntity(FAQ, PAGE_URL),
    ],
  };

  return (
    <>
      <JsonLd code={structuredData} />
      <div className="space-y-2">
        {sortedPages.length === 0 ? (
          <div className="rounded-xs border border-transparent bg-card/40 p-4">
            <h2 className="mb-4 font-semibold text-sm">Coming soon</h2>
            <p className="text-muted-foreground text-sm leading-relaxed">
              We're preparing news and updates about Lightfast. Check back soon
              for product announcements, feature releases, and insights from the
              Lightfast team.
            </p>
          </div>
        ) : (
          sortedPages.map((page) => (
            <article
              className="rounded-xs border border-transparent bg-card p-4 transition-colors hover:border-border/40"
              key={page.slugs[0]}
            >
              <NavLink
                className="group block"
                href={`/blog/${page.slugs[0]}` as Route}
              >
                <h2 className="mb-1 font-base text-md transition-colors group-hover:text-foreground/80">
                  {page.data.title}
                </h2>
                <p className="mb-4 text-md text-muted-foreground leading-relaxed">
                  {page.data.description}
                </p>
                <div className="flex items-center gap-2 text-muted-foreground text-sm">
                  <span>{page.data.category}</span>
                  <span>·</span>
                  <time dateTime={page.data.publishedAt}>
                    {new Date(page.data.publishedAt).toLocaleDateString(
                      "en-US",
                      { year: "numeric", month: "short", day: "numeric" }
                    )}
                  </time>
                </div>
              </NavLink>
            </article>
          ))
        )}
      </div>
    </>
  );
}

import { Button } from "@repo/ui/components/ui/button";
import type { GraphContext } from "@vendor/seo/json-ld";
import { JsonLd } from "@vendor/seo/json-ld";
import { RssIcon } from "lucide-react";
import type { Metadata, Route } from "next";
import Image from "next/image";
import { getChangelogPages } from "~/app/(app)/(content)/_lib/source";
import { NavLink } from "~/components/nav-link";
import {
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "~/lib/builders";
import { createMetadata } from "~/lib/content-seo";

export const dynamic = "force-static";

const PAGE_TITLE = "Changelog";
const PAGE_DESCRIPTION =
  "Every feature, improvement, fix, and breaking change shipped in Lightfast. Follow the full release history of the superintelligence layer.";
const PAGE_URL = "https://lightfast.ai/changelog";
const FAQ = [
  {
    question: "Where can I follow Lightfast product updates?",
    answer:
      "This changelog is the canonical source for all Lightfast releases. Each entry includes the version, change type, and a summary of what shipped.",
  },
  {
    question: "What is Lightfast?",
    answer:
      "Lightfast is an engineering intelligence platform that connects to your developer tools, processes events through a neural pipeline, and lets you query your engineering knowledge with AI.",
  },
  {
    question: "How often does Lightfast ship updates?",
    answer:
      "Lightfast ships continuously. Each release is documented here with a version number, change type (feature, improvement, fix, or breaking change), and detailed release notes.",
  },
  {
    question: "What integrations does Lightfast support?",
    answer:
      "Lightfast integrates with GitHub, Vercel, Linear, and Sentry via OAuth. Events flow in real-time through webhooks and are processed by the neural pipeline.",
  },
  {
    question: "Does Lightfast have an API?",
    answer:
      "Yes. Lightfast ships with a public REST API, a TypeScript SDK (lightfast on npm), and an MCP server (@lightfastai/mcp) for AI agent integration.",
  },
];

export const metadata: Metadata = createMetadata({
  title: `${PAGE_TITLE} | Lightfast`,
  description: PAGE_DESCRIPTION,
  keywords: [
    "lightfast changelog",
    "release notes",
    "product updates",
    "version history",
  ],
  alternates: {
    canonical: PAGE_URL,
    types: {
      "application/rss+xml": [
        { url: "https://lightfast.ai/changelog/rss.xml", title: "RSS 2.0" },
      ],
      "application/atom+xml": [
        { url: "https://lightfast.ai/changelog/atom.xml", title: "Atom 1.0" },
      ],
    },
  },
  openGraph: {
    title: "Lightfast Changelog",
    description: PAGE_DESCRIPTION,
    type: "website",
    url: PAGE_URL,
    siteName: "Lightfast",
    locale: "en_US",
  },
  twitter: {
    card: "summary_large_image",
    title: "Lightfast Changelog",
    description: PAGE_DESCRIPTION,
    site: "@lightfastai",
    creator: "@lightfastai",
  },
});

export default function ChangelogPage() {
  const pages = getChangelogPages();

  const sortedPages = [...pages].sort((a, b) => {
    return (
      new Date(b.data.publishedAt).getTime() -
      new Date(a.data.publishedAt).getTime()
    );
  });

  const structuredData: GraphContext = {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      {
        "@type": "WebPage" as const,
        "@id": `${PAGE_URL}#webpage`,
        url: PAGE_URL,
        name: "Lightfast Changelog",
        description: PAGE_DESCRIPTION,
        isPartOf: { "@id": "https://lightfast.ai/#website" },
        publisher: { "@id": "https://lightfast.ai/#organization" },
      },
      buildFaqEntity(FAQ, PAGE_URL),
    ],
  };

  return (
    <div className="mx-auto w-full min-w-0 max-w-2xl pt-24 pb-32">
      <JsonLd code={structuredData} />
      <div className="mb-12 flex items-center justify-between">
        <h1 className="font-medium font-pp text-3xl text-foreground">
          Changelog
        </h1>
        <NavLink
          className="inline-flex items-center gap-2 text-muted-foreground text-sm transition-colors hover:text-foreground"
          href={"/changelog/rss.xml" as Route}
          title="Subscribe to RSS Feed"
        >
          <RssIcon className="h-4 w-4" />
          <span>RSS Feed</span>
        </NavLink>
      </div>
      <div className="space-y-12 text-foreground">
        {sortedPages.length === 0 ? (
          <div className="py-16">
            <h2 className="mb-4 font-semibold text-2xl">Stay tuned</h2>
            <p className="text-foreground/80 leading-relaxed">
              We're shipping fast. Changelog entries will appear here after our
              next release.
            </p>
          </div>
        ) : (
          sortedPages.map((page) => (
            <article className="space-y-3" key={page.slugs[0]}>
              <p className="text-muted-foreground text-sm">
                Changelog
                {page.data.version ? <> / {page.data.version}</> : null}
              </p>

              <h2 className="pb-4 font-medium font-pp text-2xl">
                <Button
                  asChild
                  className="h-auto p-0 font-medium font-pp text-2xl"
                  variant="link"
                >
                  <NavLink href={`/changelog/${page.slugs[0]}` as Route}>
                    {page.data.title}
                  </NavLink>
                </Button>
              </h2>

              {page.data.featuredImage && (
                <div className="relative aspect-video w-full overflow-hidden rounded-lg bg-card">
                  <Image
                    alt={page.data.title}
                    className="h-full w-full object-cover"
                    fill
                    src={page.data.featuredImage}
                  />
                </div>
              )}

              <p className="text-muted-foreground text-sm">
                {page.data.authors[0]?.name ?? "Lightfast"} ·{" "}
                <time dateTime={page.data.publishedAt}>
                  {new Date(page.data.publishedAt).toLocaleDateString(
                    undefined,
                    { year: "numeric", month: "short", day: "numeric" }
                  )}
                </time>
              </p>

              {page.data.description && (
                <p className="pt-4 text-muted-foreground text-sm leading-relaxed">
                  {page.data.description}
                </p>
              )}
            </article>
          ))
        )}
      </div>
    </div>
  );
}

